"""In-memory user database for the auth example.

Each user record stores the salt and the derived hash separately. The
hash is PBKDF2-HMAC-SHA256 (stdlib-only, see ``auth.hash_password``).

Password for every seeded user is ``"correct-horse-battery-staple"``.
"""

from __future__ import annotations

from dataclasses import dataclass


@dataclass
class User:
    email: str
    salt: bytes      # 16 random bytes
    pw_hash: bytes   # 32 bytes (PBKDF2-HMAC-SHA256 at 100_000 iterations)


# Pre-computed salts and hashes so tests don't need to hash on import.
# Generated by ``auth.hash_password("correct-horse-battery-staple", salt)``
# from the reference implementation — see _reference/seed_hash.py.
_USERS: dict[str, User] = {
    "ada@example.com": User(
        email="ada@example.com",
        salt=bytes.fromhex("00112233445566778899aabbccddeeff"),
        pw_hash=bytes.fromhex(
            "5984471119d6c3b29dfce23aca0e6b4511e61eab963c453c6fa7db8b1df2e7c3"
        ),
    ),
    "grace@example.com": User(
        email="grace@example.com",
        salt=bytes.fromhex("fedcba9876543210fedcba9876543210"),
        pw_hash=bytes.fromhex(
            "6a1734b8d7872e6556f1eb8e9e384cbf6c2b15f8dab12f62bd5c04a227193c4c"
        ),
    ),
}


def get_user(email: str) -> User | None:
    return _USERS.get(email)
